diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..ec960dac6bf2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1250,6 +1250,7 @@ Instruction *InstCombinerImpl::visitShl(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   if (Value *V = simplifyLShrInst(I.getOperand(0), I.getOperand(1), I.isExact(),
                                   SQ.getWithInstruction(&I)))
@@ -1561,6 +1562,38 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       Value *And = Builder.CreateAnd(BoolX, BoolY);
       return new ZExtInst(And, Ty);
     }
+
+    // Reduce add-carry of low bits and/or bools to logic:
+    // ((X & 1) + (Y & 1)) >> 1 --> (X & 1) & Y
+    // ((X & 1) + (zext i1 Y)) >> 1 --> X & (zext i1 Y)
+    if (ShAmtC == 1 && match(Op0, m_Add(m_Value(X), m_Value(Y)))) {
+      Value *SrcX, *SrcY;
+      bool IsAndX = match(X, m_And(m_Value(SrcX), m_SpecificInt(1)));
+      bool IsAndY = match(Y, m_And(m_Value(SrcY), m_SpecificInt(1)));
+      bool IsZExtX = match(X, m_ZExt(m_Value(BoolX))) &&
+                     BoolX->getType()->isIntOrIntVectorTy(1);
+      bool IsZExtY = match(Y, m_ZExt(m_Value(BoolY))) &&
+                     BoolY->getType()->isIntOrIntVectorTy(1);
+
+      if ((IsAndX || IsZExtX) && (IsAndY || IsZExtY) &&
+          (X->hasOneUse() || Y->hasOneUse() || Op0->hasOneUse())) {
+        Value *OpL = X;
+        Value *OpR = Y;
+        // If X is 'and', we can use SrcX (which might simplify the 'and' away).
+        // But we can only use SrcX if the other operand (OpR) is boolean
+        // (OpR & 1 == OpR), which ensures the result is masked.
+        // If OpR is 'zext i1', it is boolean. If OpR is 'and ... 1', it is boolean.
+        bool CanUseSrcX = IsAndX;
+        bool CanUseSrcY = IsAndY;
+
+        if (CanUseSrcY && Y->hasOneUse())
+          OpR = SrcY;
+        else if (CanUseSrcX && X->hasOneUse())
+          OpL = SrcX;
+
+        return BinaryOperator::CreateAnd(OpL, OpR);
+      }
+    }
   }

   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -1586,6 +1619,7 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *
 InstCombinerImpl::foldVariableSignZeroExtensionOfVariableHighBitExtract(
     BinaryOperator &OldAShr) {

